from __future__ import annotations
ITEMS=["Confirm this decision package is manual-only.","Confirm this package does not enable live trading.","Confirm Risk Gate evidence is present and no bypass exists.","Confirm Human Approval evidence is present and explicit.","Confirm Paper Trading evidence is dry-run/local only.","Confirm Live Readiness Audit has no critical failures.","Confirm Monitoring has no CRITICAL alerts and Circuit Breaker is not OPEN.","Confirm Data Quality Tracking is acceptable for manual review.","Confirm Agent Research is read-only.","Confirm Live Gray Readiness does not auto-GO.","Confirm Notification Dry Run did not send real messages.","Confirm Dashboard is read-only and has no order entry.","Confirm Gray Rehearsal was completed.","Confirm no xttrader or QMT trading API was called.","Confirm no order was submitted.","Confirm operator manually accepts residual risk before any future separate stage."]
def default_gray_decision_checklist_items(): return list(ITEMS)
def build_gray_decision_checklist(package): return default_gray_decision_checklist_items()
def format_gray_decision_checklist(package): return "\n".join(f"- [ ] {x}" for x in (package.checklist or default_gray_decision_checklist_items()))
